INSERT INTO passage_questions (id, passage_id, question_number, question_type, question_text, explanation, correct_choice) VALUES
(64, 22, 1, 'comprehension',
'What did the research by Kahneman and Tversky primarily demonstrate?',
'第2段落で、カーネマンとトヴェルスキーの研究は「個人が不確実性に直面した際に日常的にerroneous judgmentsを下す」ことを明らかにしたと述べられている。具体的には、確率の過大・過小評価や損失回避などの体系的バイアスを実証した。選択肢3が「人間は不確実性の下で体系的に偏った判断を下す」と正確に要約。選択肢1は「合理的行為者モデルが正しい」で逆。選択肢2は「感情が経済に影響しない」で逆。選択肢4は「古典的モデルを支持する証拠が増えた」で逆。',
3),
(65, 22, 2, 'comprehension',
'Which of the following is mentioned as a criticism of nudge policies?',
'第4段落で複数の批判が挙げられている。リバタリアン学者はナッジがパターナリズムの一形態で個人の自由を侵害すると主張。また、ナッジが持続的な行動変容を生むか疑問視する者や、ナッジへの過度の依存が構造的経済不平等への対処を政府が回避することを可能にするかもしれないという懸念もある。選択肢1が「たとえ穏当に見えても、ナッジは個人の自由を侵害するパターナリズムの一形態」と批判を正確に反映。選択肢2は「ナッジは高コスト」で本文にない。選択肢3は「発展途上国でしか機能しない」で本文にない。選択肢4は「行動バイアスが存在しないと証明された」で本文と逆。',
1),
(66, 22, 3, 'fill_in_blank',
'Choose the best option to fill in the blank [BLANK] in the passage.',
'空所は第3段落にあり、ナッジ介入について「支持者はそのような介入は[BLANK]であると主張する。なぜなら個人の自律性を維持しながら、人々を長期的利益に反する行動に導く認知バイアスに対処するからである」という文脈。自由を制限せず有益な方向に導くという特徴は「倫理的に正当化できる」という評価に最もよく合致する。選択肢3「ethically justifiable」が適切。選択肢1「economically insignificant」は文脈に合わない。選択肢2「legally mandatory」はナッジの自発性と矛盾。選択肢4「universally unpopular」は支持者の立場と矛盾。',
3);

